"""Generate ``registry/*.json`` from the runtime code (vNext §19.3).

Every file starts with a machine-readable banner + timestamp.  Downstream
consumers (README, wiki, CLI help, release notes) read from these files;
if they diverge from generated output, CI fails.
"""

from __future__ import annotations

import json
from datetime import datetime, timezone
from pathlib import Path

BANNER = (
    "// GENERATED BY ZEREF (zeref.registry). "
    "SOURCE: runtime code. DO NOT EDIT DIRECTLY.\n"
)


class RegistryGenerationError(RuntimeError):
    pass


def _now() -> str:
    return datetime.now(timezone.utc).isoformat(timespec="seconds")


def _write(target: Path, payload: dict) -> Path:
    target.parent.mkdir(parents=True, exist_ok=True)
    # JSON with a leading //-banner is not strictly valid JSON, so we
    # emit the banner as a top-level "$comment" field instead.
    payload["$comment"] = BANNER.strip("\n/ ")
    payload["$generated_at"] = _now()
    target.write_text(
        json.dumps(payload, indent=2, sort_keys=True), encoding="utf-8"
    )
    return target


# ---------------------------------------------------------------------------
# Per-domain generators
# ---------------------------------------------------------------------------

def generate_components(root: Path) -> Path:
    """Runtime / adapter / contract / experimental status per module."""
    from zeref.core.reasoning import REASONING_CLASSES  # type: ignore  # noqa
    components = [
        {"id": "zeref.storage",      "status": "runtime",     "purpose": "canonical SQLite v2 + hash-chained JSONL"},
        {"id": "zeref.policy",       "status": "runtime",     "purpose": "policy precedence + autonomy modes"},
        {"id": "zeref.capabilities", "status": "runtime",     "purpose": "manifest + lifecycle + gate"},
        {"id": "zeref.adapters.capabilities", "status": "runtime", "purpose": "capability adapters (skill/agent/cli/mcp/repo)"},
        {"id": "zeref.missions",     "status": "runtime",     "purpose": "mission blueprint loader"},
        {"id": "zeref.execution_policies", "status": "runtime", "purpose": "execution policy loader"},
        {"id": "zeref.teams",        "status": "runtime",     "purpose": "team compiler + resolver"},
        {"id": "zeref.runtime",      "status": "runtime",     "purpose": "supervisor + state machines"},
        {"id": "zeref.codecs",       "status": "runtime",     "purpose": "codec registry + selector"},
        {"id": "zeref.context",      "status": "runtime",     "purpose": "6-section context packet"},
        {"id": "zeref.evidence",     "status": "runtime",     "purpose": "quality vs robustness"},
        {"id": "zeref.adapters.harnesses", "status": "adapter", "purpose": "codex/claude/gemini/kimi/hermes/odysseus"},
        {"id": "zeref.adapters.providers", "status": "adapter", "purpose": "anthropic/openai/xai config"},
        {"id": "zeref.benchmark.program", "status": "runtime", "purpose": "benchmark registry + §16.10 artifacts"},
    ]
    return _write(root / "registry" / "components.json",
                  {"schema": "zeref.registry-components/v1",
                   "components": components})


def generate_missions(root: Path) -> Path:
    from zeref.missions import load_all
    missions = load_all(root)
    payload = {
        "schema": "zeref.registry-missions/v1",
        "missions": [
            {"id": m.id, "version": m.version,
             "seats": [s["id"] for s in m.required_seats],
             "outputs": m.required_outputs}
            for m in missions
        ],
    }
    return _write(root / "registry" / "missions.json", payload)


def generate_adapters(root: Path) -> Path:
    from zeref.adapters.harnesses import detect_all
    from zeref.adapters.capabilities import list_adapters
    payload = {
        "schema": "zeref.registry-adapters/v1",
        "harness_adapters": [
            {"name": r.name, "enforcement_level": r.enforcement_level.value,
             "supported_features": list(r.supported_features)}
            for r in detect_all()
        ],
        "capability_adapters": list_adapters(),
    }
    return _write(root / "registry" / "adapters.json", payload)


def generate_codecs(root: Path) -> Path:
    from zeref.codecs import list_codecs
    return _write(root / "registry" / "codecs.json",
                  {"schema": "zeref.registry-codecs/v1",
                   "codecs": list_codecs()})


def generate_capabilities(root: Path) -> Path:
    from zeref.capabilities.store import CapabilityStore
    store = CapabilityStore(root)
    try:
        rows = store.list()
    finally:
        store.close()
    return _write(root / "registry" / "capabilities.json",
                  {"schema": "zeref.registry-capabilities/v1",
                   "capabilities": rows})


def generate_all(root: Path | str) -> list[Path]:
    root = Path(root)
    return [
        generate_components(root),
        generate_missions(root),
        generate_adapters(root),
        generate_codecs(root),
        generate_capabilities(root),
    ]
